                    .foregroundColor(.secondary)
                    .padding(.horizontal)

                if let message {
                    Text(message)
                        .font(.subheadline)
                        .foregroundColor(.red)
                        .multilineTextAlignment(.center)
                        .padding(.horizontal)
                }

                if authManager.biometricAvailable {
                    Button {
                        authenticate()
                    } label: {
                        HStack {
                            if isAuthenticating {
                                ProgressView()
                                    .progressViewStyle(.circular)
                            }
                            Text("Continue with \(biometricDisplayName)")
                                .fontWeight(.semibold)
                        }
                        .frame(maxWidth: .infinity)
                        .padding()
                    }
                    .buttonStyle(.borderedProminent)
                    .disabled(isAuthenticating)
                    .padding(.horizontal)
