                        .textContentType(.password)
                        .padding()
                        .background(Color(.secondarySystemBackground))
                        .cornerRadius(12)

                    Button {
                        loginWithPassword()
                    } label: {
                        Text("Sign In with Password")
                            .frame(maxWidth: .infinity)
                            .padding()
                    }
                    .buttonStyle(.bordered)
                }
                .padding(.horizontal)

                if authManager.biometricAvailable {
                    Button("Try Biometrics Again") {
                        authenticate()
                    }
                    .disabled(isAuthenticating)
                }

                Spacer()
            }
            .padding()
            .navigationBarHidden(true)
            .onAppear {
                authManager.refreshBiometricAvailability()
                if message == nil {
                    authenticate()
                }
            }
        }
    }

    private var biometricDisplayName: String {
        switch authManager.biometricType {
        case .faceID:
            return "Face ID"
        case .touchID:
            return "Touch ID"
        default:
            return "Biometrics"
        }
    }

    private var iconName: String {
        switch authManager.biometricType {
        case .faceID:
            return "faceid"
        case .touchID:
            return "touchid"
        default:
            return "lock.shield"
        }
